  1210→{
  1211→	if (chip->initialized)
  1212→		return;
  1213→
  1214→	/* reset controller */
  1215→	azx_reset(chip, full_reset);
  1216→
  1217→	/* initialize interrupts */
  1218→	azx_int_clear(chip);
  1219→	azx_int_enable(chip);
  1220→
  1221→	/* initialize the codec command I/O */
  1222→	if (!chip->single_cmd)
  1223→		azx_init_cmd_io(chip);
  1224→
  1225→	/* program the position buffer */
  1226→	azx_writel(chip, DPLBASE, (u32)chip->posbuf.addr);
  1227→	azx_writel(chip, DPUBASE, upper_32_bits(chip->posbuf.addr));
  1228→
